const html = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>ClaimBack — Fight Your Health Insurance Rejection</title>\n  <meta name=\"description\" content=\"AI reads your health insurance rejection letter, checks IRDAI law, and drafts your appeal in 3 minutes. No lawyer needed.\" />\n  <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\" />\n  <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin />\n  <link href=\"https://fonts.googleapis.com/css2?family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&family=DM+Sans:wght@400;500;600;700&family=DM+Mono:wght@400;500&display=swap\" rel=\"stylesheet\" />\n  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n    :root {\n      --navy:#06195e; --blue:#0b2d91; --blue3:#3d6cf5;\n      --gold:#c8920c; --gold2:#f0b429; --green:#059669;\n      --red:#dc2626; --grey1:#f4f6fb; --grey2:#e8edf5; --grey3:#9ca3af; --text:#1a1f36;\n    }\n    html { scroll-behavior: smooth; }\n    body { font-family:'DM Sans',sans-serif; color:var(--text); background:#fff; line-height:1.6; overflow-x:hidden; }\n\n    @keyframes fadeUp   { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:translateY(0)} }\n    @keyframes fadeIn   { from{opacity:0} to{opacity:1} }\n    @keyframes float    { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-8px)} }\n    @keyframes pulse    { 0%,100%{transform:scale(1)} 50%{transform:scale(1.04)} }\n    @keyframes shimmer  { 0%{background-position:-400px 0} 100%{background-position:400px 0} }\n\n    .reveal { opacity:0; transform:translateY(28px); transition:opacity .6s ease,transform .6s ease; }\n    .reveal.visible { opacity:1; transform:translateY(0); }\n\n    /* NAV */\n    nav {\n      position:sticky; top:0; z-index:100;\n      background:var(--navy);\n      display:flex; align-items:center; justify-content:space-between;\n      padding:0 5%; height:64px;\n      box-shadow:0 2px 20px rgba(6,25,94,.4);\n    }\n    .nav-logo { font-family:'Libre Baskerville',serif; font-size:1.2rem; font-weight:700; color:#fff; text-decoration:none; }\n    .nav-logo span { color:var(--gold); }\n    .nav-links { display:flex; align-items:center; gap:24px; }\n    .nav-links a { color:rgba(255,255,255,.65); font-size:.875rem; text-decoration:none; transition:color .2s; }\n    .nav-links a:hover { color:#fff; }\n    nav a.cta-btn {\n      background:var(--gold); color:#fff; font-size:.875rem; font-weight:600;\n      padding:9px 22px; border-radius:6px; text-decoration:none;\n      transition:background .2s,transform .15s;\n      animation:pulse 3s ease-in-out infinite;\n    }\n    nav a.cta-btn:hover { background:#b07d0a; transform:scale(1.04); animation:none; }\n\n    /* HERO */\n    .hero {\n      background:linear-gradient(160deg,var(--navy) 0%,#0e3399 60%,#1a47cc 100%);\n      color:#fff; padding:90px 5% 80px; text-align:center;\n      position:relative; overflow:hidden;\n    }\n    .hero::before {\n      content:''; position:absolute; inset:0;\n      background:radial-gradient(ellipse 80% 60% at 50% 0%,rgba(61,108,245,.25) 0%,transparent 70%);\n      pointer-events:none;\n    }\n    .orb { position:absolute; border-radius:50%; opacity:.07; pointer-events:none; animation:float 6s ease-in-out infinite; }\n    .orb1{width:320px;height:320px;background:var(--blue3);top:-80px;left:-60px;animation-delay:0s}\n    .orb2{width:200px;height:200px;background:var(--gold);bottom:-40px;right:5%;animation-delay:2s}\n    .orb3{width:140px;height:140px;background:#fff;top:30%;right:8%;animation-delay:4s}\n    .hero-pill {\n      display:inline-block; background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.2);\n      font-family:'DM Mono',monospace; font-size:.72rem; letter-spacing:.08em; text-transform:uppercase;\n      color:#c7d6ff; padding:5px 16px; border-radius:20px; margin-bottom:28px;\n      animation:fadeIn .8s ease both;\n    }\n    .hero h1 {\n      font-family:'Libre Baskerville',serif;\n      font-size:clamp(2.1rem,5.5vw,3.5rem); line-height:1.18;\n      max-width:780px; margin:0 auto 22px;\n      animation:fadeUp .8s .15s ease both;\n    }\n    .hero h1 em { color:var(--gold2); font-style:normal; }\n    .hero > p {\n      font-size:1.1rem; max-width:560px; margin:0 auto 40px;\n      color:rgba(199,214,255,.85); animation:fadeUp .8s .3s ease both;\n    }\n    .hero-btns { display:flex; gap:14px; justify-content:center; flex-wrap:wrap; animation:fadeUp .8s .45s ease both; }\n    .btn-primary {\n      background:var(--gold); color:#fff; font-size:1rem; font-weight:700;\n      padding:15px 32px; border-radius:8px; text-decoration:none;\n      transition:background .2s,transform .15s,box-shadow .2s;\n      box-shadow:0 4px 20px rgba(200,146,12,.4);\n    }\n    .btn-primary:hover { background:#b07d0a; transform:translateY(-2px); box-shadow:0 8px 28px rgba(200,146,12,.5); }\n    .btn-ghost {\n      background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.25);\n      color:#fff; font-size:1rem; font-weight:500; padding:15px 30px; border-radius:8px;\n      text-decoration:none; transition:background .2s,transform .15s;\n    }\n    .btn-ghost:hover { background:rgba(255,255,255,.18); transform:translateY(-2px); }\n    .hero-sub { margin-top:26px; font-size:.82rem; color:rgba(255,255,255,.45); animation:fadeUp .8s .6s ease both; }\n    .doc-cards {\n      display:flex; justify-content:center; gap:14px; margin-top:48px; flex-wrap:wrap;\n      animation:fadeUp .8s .7s ease both;\n    }\n    .doc-card {\n      background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.18);\n      border-radius:10px; padding:13px 18px;\n      display:flex; align-items:center; gap:10px;\n      font-size:.85rem; color:rgba(255,255,255,.85);\n      transition:background .2s,transform .2s;\n    }\n    .doc-card:hover { background:rgba(255,255,255,.16); transform:translateY(-3px); }\n    .doc-card .dicon { font-size:1.3rem; }\n    .doc-required { font-family:'DM Mono',monospace; font-size:.58rem; color:var(--gold2); display:block; letter-spacing:.04em; text-transform:uppercase; margin-top:2px; }\n\n    /* SECTION SHELL */\n    section { padding:72px 5%; }\n    .section-inner { max-width:920px; margin:0 auto; }\n    .section-label { font-family:'DM Mono',monospace; font-size:.68rem; letter-spacing:.12em; text-transform:uppercase; color:var(--blue3); margin-bottom:10px; }\n    h2 { font-family:'Libre Baskerville',serif; font-size:clamp(1.6rem,3.5vw,2.3rem); color:var(--navy); line-height:1.22; margin-bottom:16px; }\n    .section-sub { font-size:1rem; color:#555; max-width:600px; }\n\n    /* WHY CLAIMBACK */\n    .why-grid { display:grid; grid-template-columns:1fr 1fr; gap:18px; margin-top:40px; }\n    @media(max-width:600px){.why-grid{grid-template-columns:1fr}}\n    .why-card {\n      border:1px solid var(--grey2); border-radius:12px; padding:22px;\n      transition:transform .2s,box-shadow .2s;\n    }\n    .why-card:hover { transform:translateY(-3px); box-shadow:0 8px 24px rgba(6,25,94,.08); }\n    .why-card .icon { font-size:1.6rem; margin-bottom:10px; }\n    .why-card h4 { font-family:'Libre Baskerville',serif; color:var(--navy); margin-bottom:6px; font-size:1rem; }\n    .why-card p { font-size:.88rem; color:#555; }\n\n    /* FUNNEL — compact horizontal */\n    .funnel-section { background:var(--navy); color:#fff; padding:72px 5%; }\n    .funnel-section .section-label { color:var(--gold2); }\n    .funnel-section h2 { color:#fff; margin-bottom:44px; }\n    .funnel-inner { max-width:920px; margin:0 auto; }\n\n    .stat-cascade {\n      display:grid; grid-template-columns:repeat(4,1fr); gap:0;\n      border:1px solid rgba(255,255,255,.1); border-radius:14px; overflow:hidden;\n      margin-bottom:36px;\n    }\n    @media(max-width:700px){.stat-cascade{grid-template-columns:1fr 1fr}}\n    .stat-col {\n      padding:24px 18px; border-right:1px solid rgba(255,255,255,.08);\n      position:relative; transition:background .2s;\n    }\n    .stat-col:last-child { border-right:none; }\n    .stat-col:hover { background:rgba(255,255,255,.04); }\n    .stat-col .s-label { font-family:'DM Mono',monospace; font-size:.62rem; letter-spacing:.08em; text-transform:uppercase; color:rgba(255,255,255,.45); margin-bottom:8px; }\n    .stat-col .s-val { font-family:'Libre Baskerville',serif; font-size:1.6rem; font-weight:700; line-height:1.1; margin-bottom:4px; }\n    .stat-col .s-sub { font-size:.75rem; color:rgba(255,255,255,.5); }\n    .stat-col .s-arrow {\n      position:absolute; right:-1px; top:50%; transform:translateY(-50%);\n      width:0; height:0;\n      border-top:10px solid transparent; border-bottom:10px solid transparent;\n      border-left:10px solid rgba(255,255,255,.1);\n      z-index:2;\n      display:none;\n    }\n    @media(min-width:701px){ .stat-col:not(:last-child) .s-arrow{display:block} }\n\n    /* rejection reasons — compact tags */\n    .reasons-grid {\n      display:flex; flex-wrap:wrap; gap:10px; margin-bottom:36px;\n    }\n    .reason-tag {\n      background:rgba(255,255,255,.07); border:1px solid rgba(255,255,255,.12);\n      border-radius:8px; padding:8px 14px;\n      display:flex; align-items:center; gap:10px;\n    }\n    .reason-tag .r-pct { font-family:'DM Mono',monospace; font-size:.8rem; color:var(--gold2); font-weight:500; min-width:30px; }\n    .reason-tag .r-name { font-size:.82rem; color:rgba(255,255,255,.8); }\n\n    /* cost compare */\n    .cost-compare { display:grid; grid-template-columns:1fr 1fr; gap:16px; }\n    @media(max-width:560px){.cost-compare{grid-template-columns:1fr}}\n    .cost-card { padding:22px; border-radius:12px; text-align:center; }\n    .cost-card.them { background:rgba(220,38,38,.15); border:1px solid rgba(220,38,38,.3); }\n    .cost-card.us   { background:rgba(5,150,105,.15); border:2px solid rgba(5,150,105,.5); }\n    .cost-card .cost-label { font-family:'DM Mono',monospace; font-size:.62rem; letter-spacing:.06em; text-transform:uppercase; color:rgba(255,255,255,.45); margin-bottom:8px; }\n    .cost-card .cost-num { font-family:'Libre Baskerville',serif; font-size:2rem; font-weight:700; }\n    .cost-card.them .cost-num { color:#f87171; }\n    .cost-card.us   .cost-num { color:#34d399; }\n    .cost-card .cost-note { font-size:.76rem; color:rgba(255,255,255,.45); margin-top:6px; }\n\n    /* HOW IT WORKS */\n    .steps { display:flex; gap:24px; margin-top:44px; flex-wrap:wrap; }\n    .step {\n      flex:1 1 200px; background:var(--grey1); border:1px solid var(--grey2);\n      border-radius:12px; padding:26px 20px;\n      transition:transform .2s,box-shadow .2s;\n    }\n    .step:hover { transform:translateY(-4px); box-shadow:0 12px 32px rgba(6,25,94,.1); }\n    .step-num { font-family:'DM Mono',monospace; font-size:.68rem; color:var(--blue3); margin-bottom:10px; letter-spacing:.05em; }\n    .step-icon { font-size:1.8rem; margin-bottom:10px; }\n    .step h3 { font-family:'Libre Baskerville',serif; font-size:1.02rem; color:var(--navy); margin-bottom:7px; }\n    .step p { font-size:.86rem; color:#555; }\n    .doc-tags { display:flex; flex-wrap:wrap; gap:5px; margin-top:10px; }\n    .doc-tag { background:#fff; border:1px solid var(--grey2); border-radius:20px; padding:2px 9px; font-size:.7rem; color:var(--navy); font-weight:500; }\n    .doc-tag.req { border-color:var(--blue3); color:var(--blue3); }\n\n    /* SAMPLE OUTPUT */\n    .output-preview {\n      margin-top:44px; background:var(--grey1); border:1px solid var(--grey2);\n      border-radius:16px; padding:28px; position:relative;\n    }\n    .output-preview::before {\n      content:'SAMPLE OUTPUT — ILLUSTRATIVE ONLY';\n      position:absolute; top:14px; right:16px;\n      font-family:'DM Mono',monospace; font-size:.58rem; color:var(--grey3); letter-spacing:.06em;\n    }\n    .score-row { display:flex; align-items:center; gap:22px; margin-bottom:22px; flex-wrap:wrap; }\n    .score-circle {\n      width:92px; height:92px; border-radius:50%;\n      background:conic-gradient(var(--green) 0% 74%,var(--grey2) 74% 100%);\n      display:flex; align-items:center; justify-content:center; flex-shrink:0;\n    }\n    .score-circle-inner {\n      width:70px; height:70px; border-radius:50%; background:var(--grey1);\n      display:flex; flex-direction:column; align-items:center; justify-content:center;\n    }\n    .score-num { font-family:'Libre Baskerville',serif; font-size:1.45rem; font-weight:700; color:var(--green); line-height:1; }\n    .score-lbl { font-family:'DM Mono',monospace; font-size:.55rem; color:var(--grey3); letter-spacing:.04em; }\n    .score-meta h4 { font-family:'Libre Baskerville',serif; color:var(--navy); font-size:1.05rem; margin-bottom:5px; }\n    .score-meta p { font-size:.84rem; color:#555; }\n    .est-row { display:flex; gap:14px; margin-bottom:18px; flex-wrap:wrap; }\n    .est-card { flex:1 1 150px; background:#fff; border:1px solid var(--grey2); border-radius:10px; padding:14px 16px; }\n    .est-card .est-label { font-family:'DM Mono',monospace; font-size:.6rem; text-transform:uppercase; letter-spacing:.06em; color:var(--grey3); margin-bottom:5px; }\n    .est-card .est-val { font-family:'Libre Baskerville',serif; font-size:1.35rem; color:var(--navy); font-weight:700; }\n    .est-card .est-sub { font-size:.72rem; color:var(--grey3); margin-top:2px; }\n    .confidence-nudge {\n      background:#fff8e1; border:1px solid #f5c842; border-radius:10px; padding:14px 16px;\n      display:flex; gap:10px; align-items:flex-start; font-size:.86rem; color:#7a5a00; margin-bottom:16px;\n    }\n    .confidence-nudge .nudge-icon { font-size:1.1rem; flex-shrink:0; }\n    .confidence-nudge strong { display:block; margin-bottom:3px; }\n    .rerun-note {\n      background:#f0f4ff; border:1px solid var(--grey2); border-radius:8px;\n      padding:12px 16px; font-size:.8rem; color:#444;\n    }\n    .rerun-note strong { color:var(--navy); }\n\n    /* PRICING */\n    .pricing-cards { display:flex; gap:22px; margin-top:44px; flex-wrap:wrap; align-items:flex-start; }\n    .price-card {\n      flex:1 1 230px; border:1px solid var(--grey2); border-radius:14px; padding:28px 24px;\n      transition:transform .2s,box-shadow .2s;\n    }\n    .price-card:hover { transform:translateY(-4px); box-shadow:0 16px 40px rgba(6,25,94,.12); }\n    .price-card.featured {\n      border:2px solid var(--blue3);\n      background:linear-gradient(135deg,#f0f4ff 0%,#e8f0ff 100%);\n      position:relative;\n    }\n    .price-card.featured::before {\n      content:'RECOMMENDED'; position:absolute; top:-11px; left:50%; transform:translateX(-50%);\n      background:var(--blue3); color:#fff; font-family:'DM Mono',monospace; font-size:.58rem; letter-spacing:.1em;\n      padding:3px 12px; border-radius:20px;\n    }\n    .price-tier { font-family:'DM Mono',monospace; font-size:.65rem; letter-spacing:.08em; text-transform:uppercase; color:var(--grey3); margin-bottom:8px; }\n    .price-name { font-family:'Libre Baskerville',serif; font-size:1.2rem; color:var(--navy); margin-bottom:4px; }\n    .price-num { font-family:'Libre Baskerville',serif; font-size:2.3rem; font-weight:700; color:var(--navy); line-height:1; }\n    .price-num span { font-size:.95rem; font-weight:400; color:var(--grey3); }\n    .price-badge { display:inline-block; background:#e8f5e9; color:var(--green); font-size:.7rem; font-weight:600; padding:3px 10px; border-radius:20px; margin:7px 0 12px; }\n    .price-card.featured .price-badge { background:var(--blue3); color:#fff; }\n    .price-upgrade {\n      background:#fff8e1; border:1px solid #f5c842; border-radius:8px;\n      padding:10px 12px; margin:14px 0; font-size:.78rem; color:#7a5a00;\n    }\n    .price-upgrade strong { color:#5a4000; }\n    .price-feats { list-style:none; margin-top:12px; }\n    .price-feats li { font-size:.87rem; color:#444; padding:5px 0; border-bottom:1px solid var(--grey2); display:flex; gap:8px; align-items:flex-start; }\n    .price-feats li:last-child { border-bottom:none; }\n    .price-feats .tick { color:var(--green); font-weight:700; flex-shrink:0; }\n    .price-feats .cross { color:var(--grey3); flex-shrink:0; }\n    .price-note { font-size:.76rem; color:var(--grey3); margin-top:12px; font-style:italic; }\n\n    /* corporate tiers cards */\n    .corp-tiers { margin-top:40px; }\n    .corp-tiers h3 { font-family:'Libre Baskerville',serif; color:var(--navy); font-size:1.3rem; margin-bottom:8px; }\n    .corp-tiers p { font-size:.9rem; color:#555; margin-bottom:28px; }\n    .corp-cards { display:grid; grid-template-columns:1fr 1fr 1fr; gap:20px; margin-bottom:32px; }\n    @media(max-width:900px){.corp-cards{grid-template-columns:1fr 1fr}}\n    @media(max-width:600px){.corp-cards{grid-template-columns:1fr}}\n    .corp-card {\n      border:1px solid var(--grey2); border-radius:12px; padding:24px;\n      background:#fff; transition:transform .2s,box-shadow .2s;\n    }\n    .corp-card:hover { transform:translateY(-3px); box-shadow:0 12px 32px rgba(6,25,94,.08); }\n    .corp-card h3 { font-family:'Libre Baskerville',serif; color:var(--navy); font-size:1.08rem; margin-bottom:12px; }\n    .corp-card p { font-size:.87rem; color:#555; line-height:1.6; margin-bottom:18px; }\n    .cta-button {\n      background:var(--blue3); color:#fff; font-weight:600; font-size:.85rem;\n      padding:11px 20px; border-radius:8px; text-decoration:none; border:none; cursor:pointer;\n      transition:background .2s;\n      display:inline-block;\n    }\n    .cta-button:hover { background:var(--blue); }\n    .corp-cta {\n      margin-top:0; background:linear-gradient(135deg,var(--navy),var(--blue));\n      border-radius:12px; padding:28px; display:flex; align-items:center; justify-content:space-between; flex-wrap:wrap; gap:16px;\n    }\n    .corp-cta div h4 { font-family:'Libre Baskerville',serif; color:#fff; font-size:1.1rem; margin-bottom:4px; }\n    .corp-cta div p { color:rgba(255,255,255,.65); font-size:.85rem; }\n    .corp-cta a {\n      background:var(--gold); color:#fff; font-weight:600; font-size:.9rem;\n      padding:11px 24px; border-radius:8px; text-decoration:none; white-space:nowrap;\n      transition:background .2s;\n    }\n    .corp-cta a:hover { background:#b07d0a; }\n\n    .pricing-beta { margin-top:20px; text-align:center; font-size:.85rem; color:var(--grey3); }\n\n    /* COMPARE */\n    .compare-wrap { overflow-x:auto; margin-top:40px; border-radius:10px; border:1px solid var(--grey2); }\n    table { width:100%; border-collapse:collapse; min-width:480px; }\n    thead th { background:var(--navy); color:#fff; font-size:.83rem; padding:13px 16px; text-align:left; }\n    thead th.hl { background:var(--blue3); }\n    tbody tr { transition:background .15s; }\n    tbody tr:nth-child(even) { background:var(--grey1); }\n    tbody tr:hover { background:#edf0f8; }\n    tbody td { padding:12px 16px; font-size:.87rem; border-bottom:1px solid var(--grey2); }\n    tbody td.hl { font-weight:600; color:var(--blue); }\n    .tick { color:var(--green); font-weight:700; }\n    .cross { color:var(--red); }\n\n    /* INCENTIVE BANNER */\n    .incentive-section { background:linear-gradient(135deg,#fff8e1 0%,#fffbf0 100%); border-top:2px solid #f5c842; border-bottom:2px solid #f5c842; padding:56px 5%; }\n    .incentive-inner { max-width:920px; margin:0 auto; }\n    .incentive-grid { display:grid; grid-template-columns:1fr 1fr; gap:24px; margin-top:40px; }\n    @media(max-width:640px){.incentive-grid{grid-template-columns:1fr}}\n    .incentive-card {\n      background:#fff; border:1px solid #f5c842; border-radius:14px; padding:26px 22px;\n      display:flex; flex-direction:column; gap:10px;\n      transition:transform .2s,box-shadow .2s;\n    }\n    .incentive-card:hover{transform:translateY(-3px);box-shadow:0 8px 24px rgba(200,146,12,.15)}\n    .incentive-card .voucher-badge {\n      display:inline-flex; align-items:center; gap:8px;\n      background:#fff8e1; border:1px solid #f5c842; border-radius:8px;\n      padding:6px 14px; font-family:'DM Mono',monospace; font-size:.8rem;\n      color:#7a5a00; font-weight:500; width:fit-content;\n    }\n    .incentive-card .voucher-val { font-family:'Libre Baskerville',serif; font-size:1.8rem; font-weight:700; color:var(--gold); line-height:1; }\n    .incentive-card h4 { font-family:'Libre Baskerville',serif; color:var(--navy); font-size:1.05rem; }\n    .incentive-card p { font-size:.88rem; color:#555; }\n    .incentive-card .what-counts { font-family:'DM Mono',monospace; font-size:.7rem; letter-spacing:.05em; text-transform:uppercase; color:var(--green); margin-top:4px; }\n    .incentive-how {\n      margin-top:32px; background:#fff; border:1px solid var(--grey2); border-radius:12px; padding:24px 22px;\n    }\n    .incentive-how h4 { font-family:'Libre Baskerville',serif; color:var(--navy); font-size:1rem; margin-bottom:16px; }\n    .incentive-steps { display:flex; gap:0; }\n    @media(max-width:560px){.incentive-steps{flex-direction:column;gap:12px}}\n    .incentive-step { flex:1; text-align:center; padding:0 10px; position:relative; }\n    .incentive-step:not(:last-child)::after {\n      content:'→'; position:absolute; right:-8px; top:16px;\n      color:var(--grey3); font-size:1rem;\n    }\n    @media(max-width:560px){.incentive-step:not(:last-child)::after{display:none}}\n    .incentive-step .is-icon { font-size:1.5rem; margin-bottom:6px; }\n    .incentive-step .is-label { font-size:.8rem; color:#555; line-height:1.4; }\n    .incentive-disclaimer { margin-top:16px; font-size:.76rem; color:var(--grey3); font-style:italic; }\n\n    /* BETA */\n    .tester-box {\n      background:linear-gradient(135deg,var(--navy) 0%,var(--blue) 100%);\n      border-radius:16px; padding:48px 36px; color:#fff; text-align:center; margin-top:40px;\n      position:relative; overflow:hidden;\n    }\n    .tester-box::before { content:''; position:absolute; top:-60px; right:-60px; width:200px; height:200px; border-radius:50%; background:rgba(255,255,255,.04); }\n    .tester-box h3 { font-family:'Libre Baskerville',serif; font-size:1.6rem; margin-bottom:12px; }\n    .tester-box p { color:rgba(199,214,255,.85); max-width:480px; margin:0 auto 26px; }\n    .req-list { display:flex; justify-content:center; gap:10px; flex-wrap:wrap; margin-bottom:28px; }\n    .req-chip { background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.18); border-radius:20px; padding:5px 14px; font-size:.8rem; }\n\n    /* FAQ */\n    .faq-list { margin-top:38px; }\n    details { border-bottom:1px solid var(--grey2); padding:18px 0; }\n    details:first-child { border-top:1px solid var(--grey2); }\n    summary {\n      font-family:'Libre Baskerville',serif; font-size:1rem; color:var(--navy);\n      cursor:pointer; list-style:none; display:flex; justify-content:space-between; align-items:center; gap:14px;\n    }\n    summary::after { content:'+'; font-size:1.4rem; color:var(--blue3); flex-shrink:0; }\n    details[open] summary::after { content:'−'; }\n    details p { margin-top:11px; font-size:.92rem; color:#555; max-width:680px; line-height:1.65; }\n\n    /* DISCLAIMER BLOCKS */\n    .disclaimer-box {\n      border-radius:10px; padding:18px 22px; margin-bottom:14px; font-size:.86rem;\n    }\n    .disclaimer-box.warn  { background:#fff8e1; border:1px solid #f5c842; color:#7a5a00; }\n    .disclaimer-box.info  { background:#eff6ff; border:1px solid #bfdbfe; color:#1e40af; }\n    .disclaimer-box.legal { background:#f9fafb; border:1px solid var(--grey2); color:#374151; }\n    .disclaimer-box strong { display:block; margin-bottom:5px; font-size:.9rem; }\n    .disclaimers-section { margin-top:40px; }\n\n    /* FOOTER */\n    footer { background:var(--navy); color:rgba(255,255,255,.55); padding:52px 5% 28px; }\n    .footer-inner { max-width:920px; margin:0 auto; display:flex; flex-wrap:wrap; gap:36px; justify-content:space-between; }\n    .footer-brand p { margin-top:10px; font-size:.83rem; max-width:240px; }\n    .footer-col h5 { color:#fff; font-size:.83rem; font-weight:600; margin-bottom:12px; letter-spacing:.04em; }\n    .footer-col a { display:block; color:rgba(255,255,255,.5); font-size:.83rem; text-decoration:none; margin-bottom:8px; transition:color .2s; }\n    .footer-col a:hover { color:#fff; }\n    .footer-bottom {\n      max-width:920px; margin:32px auto 0;\n      border-top:1px solid rgba(255,255,255,.1); padding-top:20px;\n      display:flex; flex-wrap:wrap; gap:12px; justify-content:space-between; font-size:.76rem;\n    }\n\n    @media(max-width:720px){\n      .nav-links{display:none}\n      .steps,.pricing-cards{flex-direction:column}\n      .tester-box{padding:32px 18px}\n    }\n  </style>\n</head>\n<body>\n\n<!-- NAV -->\n<nav>\n  <a class=\"nav-logo\" href=\"#\">Claim<span>Back</span></a>\n  <div class=\"nav-links\">\n    <a href=\"#why\">Why ClaimBack</a>\n    <a href=\"#how-it-works\">How It Works</a>\n    <a href=\"#pricing\">Pricing</a>\n    <a href=\"#faq\">FAQ</a>\n  </div>\n  <a class=\"cta-btn\" href=\"/sign-up\">Join Beta →</a>\n</nav>\n\n<!-- HERO -->\n<section class=\"hero\">\n  <div class=\"orb orb1\"></div><div class=\"orb orb2\"></div><div class=\"orb orb3\"></div>\n  <div class=\"hero-pill\">🇮🇳 India's First AI Health Claim Appeal Tool</div>\n  <h1>Your insurance company said no.<br/><em>Fight back in 3 minutes.</em></h1>\n  <p>Upload your documents. Our AI reads IRDAI regulations, finds every gap in the rejection, and writes your professional appeal — with your estimated recovery amount and win probability.</p>\n  <div class=\"hero-btns\">\n    <a class=\"btn-primary\" href=\"/sign-up\">Start My Appeal — Free →</a>\n    <a class=\"btn-ghost\" href=\"#why\">See How It Works ↓</a>\n  </div>\n  <p class=\"hero-sub\">Free during beta · Works in your browser · No lawyer needed</p>\n  <div class=\"doc-cards\">\n    <div class=\"doc-card\"><span class=\"dicon\">📋</span><div>Insurance Policy<span class=\"doc-required\">Best analysis</span></div></div>\n    <div class=\"doc-card\"><span class=\"dicon\">🏥</span><div>Hospital Bills<span class=\"doc-required\">Strengthens case</span></div></div>\n    <div class=\"doc-card\"><span class=\"dicon\">✉️</span><div>Rejection / Approval Letter<span class=\"doc-required\">Minimum required</span></div></div>\n  </div>\n</section>\n\n<!-- WHY CLAIMBACK — moved up, right after hero -->\n<section id=\"why\" style=\"background:#fff;\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">Why ClaimBack</div>\n    <h2 class=\"reveal\">The system is stacked against you.<br/>We level the playing field.</h2>\n    <p class=\"section-sub reveal\">Insurance companies have legal teams. Until now, you didn't.</p>\n    <div class=\"why-grid\">\n      <div class=\"why-card reveal\">\n        <div class=\"icon\">⚡</div>\n        <h4>3 minutes vs 2 weeks</h4>\n        <p>Traditional services take 1–2 weeks. ClaimBack delivers your appeal letter and full analysis in under 3 minutes.</p>\n      </div>\n      <div class=\"why-card reveal\" style=\"transition-delay:.05s\">\n        <div class=\"icon\">🔍</div>\n        <h4>Gaps, not guesses</h4>\n        <p>We identify specific legal gaps in the insurer's reasoning — citing the exact IRDAI regulation that applies to your case, not a generic template.</p>\n      </div>\n      <div class=\"why-card reveal\" style=\"transition-delay:.1s\">\n        <div class=\"icon\">📊</div>\n        <h4>Know before you fight</h4>\n        <p>Estimated recovery amount (min–max) and win probability calculated upfront — so you go in with eyes open, not blind faith.</p>\n      </div>\n      <div class=\"why-card reveal\" style=\"transition-delay:.15s\">\n        <div class=\"icon\">🔒</div>\n        <h4>Your data stays protected</h4>\n        <p>Documents encrypted, stored in India (Mumbai), processed solely for your analysis. Compliant with India's DPDP Act 2023. We never sell your data.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FUNNEL — compact design -->\n<section class=\"funnel-section\" id=\"stats\">\n  <div class=\"funnel-inner\">\n    <div class=\"section-label reveal\">The Scale of the Problem</div>\n    <h2 class=\"reveal\">₹26,037 crore in health claims were rejected last year.<br/>Most claimants give up. You don't have to.</h2>\n\n    <div class=\"stat-cascade reveal\">\n      <div class=\"stat-col\">\n        <div class=\"s-label\">Total claims filed</div>\n        <div class=\"s-val\">₹1.10L Cr</div>\n        <div class=\"s-sub\">FY2023-24 · IRDAI Annual Report</div>\n        <div class=\"s-arrow\"></div>\n      </div>\n      <div class=\"stat-col\">\n        <div class=\"s-label\">Approved &amp; settled</div>\n        <div class=\"s-val\" style=\"color:#6ee7b7\">82%</div>\n        <div class=\"s-sub\">₹90,200 Cr paid out · IRDAI 2024</div>\n        <div class=\"s-arrow\"></div>\n      </div>\n      <div class=\"stat-col\">\n        <div class=\"s-label\">Rejected / disallowed</div>\n        <div class=\"s-val\" style=\"color:#fca5a5\">12.9%</div>\n        <div class=\"s-sub\">₹26,037 Cr · Business Standard Dec 2024</div>\n        <div class=\"s-arrow\"></div>\n      </div>\n      <div class=\"stat-col\">\n        <div class=\"s-label\">Win rate on appeal</div>\n        <div class=\"s-val\" style=\"color:#fcd34d\">~58%</div>\n        <div class=\"s-sub\">Insurance Ombudsman data 2023-24</div>\n      </div>\n    </div>\n\n    <div class=\"section-label reveal\" style=\"color:rgba(255,255,255,.45);margin-bottom:14px\">Top 5 reasons claims are rejected or partially approved</div>\n    <div class=\"reasons-grid reveal\">\n      <div class=\"reason-tag\"><span class=\"r-pct\">31%</span><span class=\"r-name\">Pre-existing disease exclusion</span></div>\n      <div class=\"reason-tag\"><span class=\"r-pct\">24%</span><span class=\"r-name\">Policy exclusion / sub-limit breach</span></div>\n      <div class=\"reason-tag\"><span class=\"r-pct\">18%</span><span class=\"r-name\">Incomplete / incorrect documentation</span></div>\n      <div class=\"reason-tag\"><span class=\"r-pct\">15%</span><span class=\"r-name\">Non-disclosure at policy issuance</span></div>\n      <div class=\"reason-tag\"><span class=\"r-pct\">12%</span><span class=\"r-name\">Waiting period not completed</span></div>\n    </div>\n\n    <div class=\"cost-compare reveal\">\n      <div class=\"cost-card them\">\n        <div class=\"cost-label\">Average cost — traditional services</div>\n        <div class=\"cost-num\">₹5,502</div>\n        <div class=\"cost-note\">₹999 fee + 15% of claim · Insurance Samadhan 2024</div>\n      </div>\n      <div class=\"cost-card us\">\n        <div class=\"cost-label\">ClaimBack flat fee</div>\n        <div class=\"cost-num\">₹999</div>\n        <div class=\"cost-note\">All 4 escalation levels · No success cut</div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- HOW IT WORKS -->\n<section id=\"how-it-works\" style=\"background:var(--grey1);\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">The Process</div>\n    <h2 class=\"reveal\">From rejection to appeal letter in under 3 minutes</h2>\n    <p class=\"section-sub reveal\">No legal jargon. No appointments. No waiting. Upload all documents before you pay — re-running analysis requires a fresh payment.</p>\n    <div class=\"steps\">\n      <div class=\"step reveal\">\n        <div class=\"step-num\">STEP 01</div><div class=\"step-icon\">📤</div>\n        <h3>Upload your documents</h3>\n        <p>More documents = higher confidence + more accurate estimate. Upload everything you have before proceeding.</p>\n        <div class=\"doc-tags\">\n          <span class=\"doc-tag req\">📋 Policy</span>\n          <span class=\"doc-tag req\">✉️ Rejection Letter</span>\n          <span class=\"doc-tag\">🏥 Hospital Bills</span>\n        </div>\n      </div>\n      <div class=\"step reveal\" style=\"transition-delay:.1s\">\n        <div class=\"step-num\">STEP 02</div><div class=\"step-icon\">🤖</div>\n        <h3>AI reads IRDAI regulations</h3>\n        <p>Cross-references your documents against IRDAI Health Insurance Regulations 2016 and Insurance Ombudsman Rules 2017 to find every gap in the rejection.</p>\n      </div>\n      <div class=\"step reveal\" style=\"transition-delay:.2s\">\n        <div class=\"step-num\">STEP 03</div><div class=\"step-icon\">⚖️</div>\n        <h3>Get estimate + appeal letter</h3>\n        <p>Win probability score, estimated recovery amount (min–max), gap analysis with regulation citations, and a professionally drafted appeal letter.</p>\n      </div>\n      <div class=\"step reveal\" style=\"transition-delay:.3s\">\n        <div class=\"step-num\">STEP 04</div><div class=\"step-icon\">📬</div>\n        <h3>Send. Escalate if needed.</h3>\n        <p>4 escalation paths with ready-to-send emails: Grievance Officer → IRDAI Bima Bharosa → Ombudsman → Consumer Court docket.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- SAMPLE OUTPUT -->\n<section id=\"output\" style=\"background:#fff;\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">What You Get</div>\n    <h2 class=\"reveal\">Estimated recovery + win probability,<br/>from AI analysis of your documents benchmarked against IRDAI regulations</h2>\n    <p class=\"section-sub reveal\">Your output — and its confidence level — depends on which documents you upload. The app will always tell you how to improve your analysis before you pay.</p>\n\n    <div class=\"output-preview reveal\">\n      <div class=\"score-row\">\n        <div class=\"score-circle\"><div class=\"score-circle-inner\"><span class=\"score-num\">74</span><span class=\"score-lbl\">WIN SCORE</span></div></div>\n        <div class=\"score-meta\">\n          <h4>Good Appeal Case · Confidence: High</h4>\n          <p>Your rejection cites a pre-existing condition exclusion, but IRDAI Regulation 8(6) limits this to conditions disclosed at policy issuance. Our analysis found 3 gaps in the insurer's reasoning.</p>\n        </div>\n      </div>\n      <div class=\"est-row\">\n        <div class=\"est-card\">\n          <div class=\"est-label\">Est. Recovery (Min)</div>\n          <div class=\"est-val\">₹1.8L</div>\n          <div class=\"est-sub\">Conservative scenario</div>\n        </div>\n        <div class=\"est-card\">\n          <div class=\"est-label\">Est. Recovery (Max)</div>\n          <div class=\"est-val\">₹2.4L</div>\n          <div class=\"est-sub\">If Level 1 succeeds</div>\n        </div>\n        <div class=\"est-card\">\n          <div class=\"est-label\">Win Probability</div>\n          <div class=\"est-val\" style=\"color:var(--green)\">74%</div>\n          <div class=\"est-sub\">Confidence: High ✓</div>\n        </div>\n      </div>\n      <div class=\"confidence-nudge\">\n        <span class=\"nudge-icon\">💡</span>\n        <div>\n          <strong>Upload hospital bills to reach Confidence: Very High</strong>\n          You've provided your policy + rejection letter. Adding itemised hospital bills lets us verify the exact billed amount vs. claimed — improving your recovery range accuracy. Act before paying: once the analysis runs, a re-run requires a fresh payment.\n        </div>\n      </div>\n      <div class=\"rerun-note\">\n        <strong>Why does a re-run cost again?</strong> Each analysis reads your documents end-to-end using AI — there's no cached \"partial result.\" Adding new documents means running the full analysis afresh. The fee reflects that real cost honestly. We surface this upfront so you upload everything before you proceed. That's just being fair.\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- PRICING -->\n<section id=\"pricing\" style=\"background:var(--grey1);\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">Pricing</div>\n    <h2 class=\"reveal\">Transparent pricing. No cuts from your recovery.</h2>\n    <p class=\"section-sub reveal\">Average claim value is ₹31,086. Spending ₹499–₹999 to fight for it is a straightforward decision — and still 5.5× cheaper than traditional services.</p>\n\n    <div class=\"pricing-cards\">\n      <!-- Starter -->\n      <div class=\"price-card reveal\">\n        <div class=\"price-tier\">Essential</div>\n        <div class=\"price-name\">Appeal Starter</div>\n        <div class=\"price-num\">₹499 <span>/case</span></div>\n        <span class=\"price-badge\">Good for clear-cut cases</span>\n        <div class=\"price-upgrade\">\n          <strong>Upgrade to Full Package anytime:</strong> pay ₹799 more (total out-of-pocket: ₹1,298). A fresh analysis runs with your complete document set.\n        </div>\n        <ul class=\"price-feats\">\n          <li><span class=\"tick\">✓</span> Full AI analysis + gap identification</li>\n          <li><span class=\"tick\">✓</span> Win probability score</li>\n          <li><span class=\"tick\">✓</span> Estimated recovery (min–max)</li>\n          <li><span class=\"tick\">✓</span> Level 1 — Grievance Officer appeal letter</li>\n          <li><span class=\"tick\">✓</span> Level 2 — IRDAI Bima Bharosa email</li>\n          <li><span class=\"cross\">—</span> Level 3 — Ombudsman complaint</li>\n          <li><span class=\"cross\">—</span> Level 4 — Consumer Court docket</li>\n        </ul>\n        <p class=\"price-note\">Upgrade anytime for ₹799 — not ₹500. Fresh analysis runs in full.</p>\n      </div>\n\n      <!-- Full -->\n      <div class=\"price-card featured reveal\" style=\"transition-delay:.1s\">\n        <div class=\"price-tier\">Complete</div>\n        <div class=\"price-name\">Full Package</div>\n        <div class=\"price-num\">₹999 <span>/case</span></div>\n        <span class=\"price-badge\">Most popular · Best value</span>\n        <ul class=\"price-feats\">\n          <li><span class=\"tick\">✓</span> Full AI analysis + gap identification</li>\n          <li><span class=\"tick\">✓</span> Win probability score</li>\n          <li><span class=\"tick\">✓</span> Estimated recovery (min–max)</li>\n          <li><span class=\"tick\">✓</span> Level 1 — Grievance Officer appeal letter</li>\n          <li><span class=\"tick\">✓</span> Level 2 — IRDAI Bima Bharosa email</li>\n          <li><span class=\"tick\">✓</span> Level 3 — Ombudsman complaint</li>\n          <li><span class=\"tick\">✓</span> Level 4 — Consumer Court full docket</li>\n        </ul>\n        <p class=\"price-note\">vs. ₹5,502 average at traditional services. 5.5× cheaper, 500× faster.</p>\n      </div>\n    </div>\n\n    <p class=\"pricing-beta reveal\">🎉 <strong>Beta is completely free.</strong> Sign up free on the web and use ClaimBack at no cost during beta.</p>\n\n    <!-- Corporate -->\n    <div class=\"corp-tiers reveal\" style=\"margin-top:56px\">\n      <h3>For HR teams managing group health claims</h3>\n      <p>Your HR department spends hours helping employees fight rejected claims. ClaimBack cuts that to minutes — per case — at a fraction of traditional service costs.</p>\n      <div class=\"corp-cards\">\n        <div class=\"corp-card reveal\">\n          <h3>Small teams<br/>(50–250 people)</h3>\n          <p>Your HR person is drowning in claim disputes on top of their regular duties. They need a tool that turns hours of research into a polished appeal letter in 3 minutes.</p>\n          <a href=\"mailto:support@claimback.co.in?subject=ClaimBack%20for%20Small%20Teams%20-%20Enquiry\" class=\"cta-button\">Discuss your plan →</a>\n        </div>\n        <div class=\"corp-card reveal\" style=\"transition-delay:.1s\">\n          <h3>Mid-market<br/>(250–1,000 people)</h3>\n          <p>Rejected claims are bleeding your benefits budget. Your HR team knows the patterns but doesn't have time to fight each one individually. ClaimBack scales their advocacy.</p>\n          <a href=\"mailto:support@claimback.co.in?subject=ClaimBack%20for%20Mid-Market%20-%20Enquiry\" class=\"cta-button\">Discuss your plan →</a>\n        </div>\n        <div class=\"corp-card reveal\" style=\"transition-delay:.2s\">\n          <h3>Enterprises<br/>(1,000+ people)</h3>\n          <p>At scale, claim rejections cost you millions annually. You need a standardised, auditable process your HR can deploy across the entire employee base — and we can customise it.</p>\n          <a href=\"mailto:support@claimback.co.in?subject=ClaimBack%20Enterprise%20-%20Enquiry\" class=\"cta-button\">Discuss your plan →</a>\n        </div>\n      </div>\n      <div class=\"corp-cta\">\n        <div>\n          <h4>Custom pricing based on your company's needs</h4>\n          <p>We'll review your group health policy, case volume, and team size to design a plan that works.</p>\n        </div>\n        <a href=\"mailto:support@claimback.co.in?subject=ClaimBack%20Corporate%20Pricing%20Enquiry\">Get Pricing →</a>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- COMPARE -->\n<section style=\"background:#fff;\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">Comparison</div>\n    <h2 class=\"reveal\">ClaimBack vs the alternatives</h2>\n    <div class=\"compare-wrap reveal\">\n      <table>\n        <thead>\n          <tr>\n            <th>Feature</th>\n            <th class=\"hl\">ClaimBack</th>\n            <th>Insurance Samadhan</th>\n            <th>Do It Yourself</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr><td>Time to appeal letter</td><td class=\"hl\">3 minutes</td><td>1–2 weeks</td><td>Days to weeks</td></tr>\n          <tr><td>Cost</td><td class=\"hl\">₹499–₹999 flat</td><td>₹999 + 15% of claim</td><td>Free (complex)</td></tr>\n          <tr><td>Estimated recovery amount</td><td class=\"hl\"><span class=\"tick\">✓</span> Yes</td><td><span class=\"cross\">✗</span> No</td><td><span class=\"cross\">✗</span> No</td></tr>\n          <tr><td>Gap analysis with IRDAI citation</td><td class=\"hl\"><span class=\"tick\">✓</span> Specific regulation</td><td><span class=\"tick\">✓</span> Yes</td><td><span class=\"cross\">✗</span> Unlikely</td></tr>\n          <tr><td>4-level escalation plan</td><td class=\"hl\"><span class=\"tick\">✓</span> Yes</td><td><span class=\"cross\">✗</span> You manage</td><td><span class=\"cross\">✗</span> You manage</td></tr>\n          <tr><td>Win probability score</td><td class=\"hl\"><span class=\"tick\">✓</span> AI-calculated</td><td><span class=\"cross\">✗</span> No</td><td><span class=\"cross\">✗</span> No</td></tr>\n        </tbody>\n      </table>\n    </div>\n  </div>\n</section>\n\n<!-- INCENTIVE / CLOSE THE LOOP -->\n<section class=\"incentive-section\" id=\"incentive\">\n  <div class=\"incentive-inner\">\n    <div class=\"section-label reveal\" style=\"color:var(--gold)\">Close the Loop · Earn a Voucher</div>\n    <h2 class=\"reveal\" style=\"color:var(--navy)\">Tell us what happened.<br/>Earn ₹200–₹300 in shopping vouchers.</h2>\n    <p class=\"section-sub reveal\">Once you've sent your appeal, come back and update your outcome. Your real-world result helps us improve accuracy for every claimant who comes after you — and we reward you for it.</p>\n\n    <div class=\"incentive-grid\">\n      <div class=\"incentive-card reveal\">\n        <div class=\"voucher-badge\">🛒 Amazon / Flipkart Voucher</div>\n        <div class=\"voucher-val\">₹200</div>\n        <h4>Any outcome update + supporting document</h4>\n        <p>Update your case status (won, lost, pending, escalated) and upload any supporting document — insurer response, TPA letter, Ombudsman acknowledgement, or any correspondence.</p>\n        <div class=\"what-counts\">✓ Even a loss counts — all outcomes are valuable</div>\n      </div>\n      <div class=\"incentive-card reveal\" style=\"transition-delay:.1s;border-color:var(--green)\">\n        <div class=\"voucher-badge\" style=\"background:#e8f5e9;border-color:var(--green);color:#065f46\">🎉 Amazon / Flipkart Voucher</div>\n        <div class=\"voucher-val\" style=\"color:var(--green)\">₹300</div>\n        <h4>Proof of settlement or approval</h4>\n        <p>Upload your settlement letter, final approval from the insurer, or payment confirmation showing the claim was resolved in your favour (full or partial).</p>\n        <div class=\"what-counts\" style=\"color:var(--green)\">✓ Highest tier — verified win proof</div>\n      </div>\n    </div>\n\n    <div class=\"incentive-how reveal\">\n      <h4>How it works</h4>\n      <div class=\"incentive-steps\">\n        <div class=\"incentive-step\"><div class=\"is-icon\">📬</div><div class=\"is-label\">Send your appeal letter from ClaimBack</div></div>\n        <div class=\"incentive-step\"><div class=\"is-icon\">⏳</div><div class=\"is-label\">Wait for insurer response (15–30 days typically)</div></div>\n        <div class=\"incentive-step\"><div class=\"is-icon\">📲</div><div class=\"is-label\">Open ClaimBack app → update your outcome → upload document</div></div>\n        <div class=\"incentive-step\"><div class=\"is-icon\">🤖</div><div class=\"is-label\">AI verifies document (48–72 hrs)</div></div>\n        <div class=\"incentive-step\"><div class=\"is-icon\">🛒</div><div class=\"is-label\">Voucher code emailed to you</div></div>\n      </div>\n      <p class=\"incentive-disclaimer\">Vouchers are issued as Amazon or Flipkart gift codes via email. One voucher per case. Verification is automated — documents are checked for authenticity by our AI. Fraudulent uploads will result in disqualification. Programme is active during beta and subject to change. No cash alternative. Not a cashback or financial service.</p>\n    </div>\n  </div>\n</section>\n\n<!-- BETA CTA -->\n<section id=\"beta\" style=\"background:var(--grey1);\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">Beta Access</div>\n    <h2 class=\"reveal\">Join the ClaimBack beta</h2>\n    <p class=\"section-sub reveal\">Invite-only. Completely free. Works right in your browser.</p>\n    <div class=\"tester-box reveal\">\n      <h3>Start Free on the Web</h3>\n      <p>No app download needed. Sign up with your email, upload your documents, and get your appeal — right from your browser.</p>\n      <div class=\"req-list\">\n        <span class=\"req-chip\">💻 Works on any device</span>\n        <span class=\"req-chip\">Phone or computer</span>\n        <span class=\"req-chip\">Free in beta</span>\n        <span class=\"req-chip\">3 mins to appeal</span>\n      </div>\n      <a class=\"btn-primary\" href=\"/sign-up\">Create Free Account →</a>\n      <p style=\"font-size:.76rem;margin-top:16px;color:rgba(255,255,255,.35);\">iOS app in beta · Android coming soon · support@claimback.co.in</p>\n    </div>\n  </div>\n</section>\n\n<!-- FAQ -->\n<section id=\"faq\" style=\"background:#fff;\">\n  <div class=\"section-inner\">\n    <div class=\"section-label reveal\">FAQ</div>\n    <h2 class=\"reveal\">Common questions</h2>\n    <div class=\"faq-list\">\n      <details>\n        <summary>Which documents should I upload for the best analysis?</summary>\n        <p>Upload all three for the most accurate result: <strong>(1) Insurance policy document</strong> — lets us cross-reference your actual coverage terms. <strong>(2) Rejection or partial approval letter</strong> — minimum required to run any analysis. <strong>(3) Itemised hospital bills</strong> — helps us verify the billed vs. claimed amount and sharpen your recovery estimate. More documents = higher confidence level and a more precise win probability. <strong>Important:</strong> upload everything before you pay. Re-running analysis requires a fresh payment because the full AI analysis must be re-executed — there is no \"top-up\" option.</p>\n      </details>\n      <details>\n        <summary>Why do I have to pay again if I want to add more documents later?</summary>\n        <p>Every analysis — including a re-run — reads your documents end-to-end using AI. There is no cached \"partial\" result we can build on. Adding new documents means running the full process again from scratch: re-reading every page, re-cross-referencing every IRDAI regulation, and regenerating your appeal letter. That costs real compute and AI processing — and we pass it on honestly rather than baking it into a higher initial price. We surface this prominently before you pay so you have every opportunity to upload all documents first. That's just being fair to you.</p>\n      </details>\n      <details>\n        <summary>What does the win probability and estimated recovery amount mean?</summary>\n        <p>The win probability (0–100%) is an AI assessment of how likely your appeal is to succeed, based on your rejection reason, policy terms, and applicable IRDAI regulations. The estimated recovery (min–max range) is derived from your claimed amount, the identified gaps, and patterns from similar appeal outcomes. <strong>Important disclaimer:</strong> these are AI-generated estimates for informational guidance only. They are not a guarantee or prediction of outcome, and do not constitute legal advice. Actual results depend on the insurer's response, the Ombudsman's discretion, and facts not visible in your documents. Confidence level (Low / Medium / High / Very High) tells you how complete your document set is for the analysis.</p>\n      </details>\n      <details>\n        <summary>What are the \"gaps\" ClaimBack identifies?</summary>\n        <p>Gaps are points where the insurer's rejection reasoning does not align with IRDAI Health Insurance Regulations 2016, your specific policy terms, or Insurance Ombudsman Rules 2017. For example: a pre-existing disease exclusion applied beyond IRDAI's permitted waiting period limits, or a sub-limit enforced without clear disclosure at policy issuance. Each gap is cited with the specific regulation number — not generic language.</p>\n      </details>\n      <details>\n        <summary>Is ClaimBack a legal service? Is it regulated?</summary>\n        <p>No. ClaimBack is an AI-powered document analysis and drafting tool — a software product, not a law firm and not an insurance intermediary. We are not regulated by IRDAI (which regulates insurance companies and licensed intermediaries). We are not regulated by the Bar Council (which regulates lawyers). Our service is informational — we help you understand your position and draft appeal documents. For complex legal proceedings, we recommend consulting a licensed insurance lawyer, particularly for Consumer Court matters.</p>\n      </details>\n      <details>\n        <summary>How is my data protected under India's DPDP Act?</summary>\n        <p>ClaimBack is committed to compliance with India's Digital Personal Data Protection Act 2023 (DPDP Act). Your documents are: (1) processed solely for generating your analysis and appeal letter; (2) stored encrypted in India (AWS Mumbai, ap-south-1); (3) never sold, shared, or used for any other purpose; (4) retained for 12 months then deleted automatically. You may request access, correction, or erasure of your data at any time by emailing support@claimback.co.in. See our full <a href=\"privacy.html\" style=\"color:var(--blue3)\">Privacy Policy</a> for details.</p>\n      </details>\n      <details>\n        <summary>How do I earn the ₹200–₹300 voucher?</summary>\n        <p>After sending your appeal, come back to the ClaimBack app and update your outcome — won, lost, pending, or escalated. Upload any document related to the outcome (insurer response, TPA letter, settlement letter, approval email, etc.). Our AI verifies the document within 48–72 hours. If it passes, we email you an Amazon or Flipkart gift voucher: <strong>₹200</strong> for any valid outcome document, <strong>₹300</strong> for a settlement letter or formal approval confirming your claim was resolved. Even if you lost, update your outcome — we value all data and still send ₹200. One voucher per case. No cash alternative. See the <a href=\"#incentive\" style=\"color:var(--blue3)\">Close the Loop</a> section above for full details.</p>\n      </details>\n      <details>\n        <summary>What if my appeal fails at all four levels?</summary>\n        <p>ClaimBack provides you with all tools and documents to pursue every available statutory remedy. If all four levels are exhausted without resolution, the Consumer Court docket we provide (Level 4) is your final formal option and requires a lawyer to represent you in proceedings. We do not provide legal representation. At that stage, we recommend engaging a licensed insurance lawyer — and we plan to partner with legal referral services to help you find one.</p>\n      </details>\n    </div>\n\n    <!-- DISCLAIMERS -->\n    <div class=\"disclaimers-section reveal\">\n      <div class=\"disclaimer-box warn\">\n        <strong>⚠️ AI Disclaimer — Estimates &amp; Probability</strong>\n        The win probability score and estimated recovery amount generated by ClaimBack are AI-derived estimates based on your uploaded documents and IRDAI regulations. They are for informational guidance only. They are not a guarantee, prediction, or legal opinion regarding your case outcome. Actual results depend on insurer discretion, Ombudsman findings, and facts that may not be present in your documents. ClaimBack accepts no liability for decisions made based on these estimates.\n      </div>\n      <div class=\"disclaimer-box info\">\n        <strong>ℹ️ Not Legal Advice</strong>\n        ClaimBack is an AI-powered document drafting tool. It does not constitute legal advice, and ClaimBack is not a law firm. The appeal letters, escalation emails, and analysis generated are starting points for your own action — review all content before sending. For legal representation in Consumer Court or complex insurance disputes, consult a licensed advocate.\n      </div>\n      <div class=\"disclaimer-box legal\">\n        <strong>⚖️ Limitation of Liability</strong>\n        ClaimBack's total liability to any user arising from use of the service is strictly limited to the fee paid for the specific case (maximum ₹999 for individual plans). ClaimBack is not liable for any indirect, consequential, special, or incidental damages including — but not limited to — loss of claim proceeds, missed deadlines, or insurer decisions. Use of this service constitutes acceptance of our full <a href=\"terms.html\" style=\"color:var(--blue3)\">Terms of Service</a>.\n      </div>\n      <div class=\"disclaimer-box legal\">\n        <strong>🔐 Data Privacy (DPDP Act 2023)</strong>\n        Your documents and personal data are processed in accordance with India's Digital Personal Data Protection Act 2023. Data is stored encrypted in India. It is used solely to generate your analysis and is not shared with third parties except as required by law or disclosed in our <a href=\"privacy.html\" style=\"color:var(--blue3)\">Privacy Policy</a>. AI processing is performed via Anthropic's Claude API — Anthropic does not use API data for model training per their published API usage policy.\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"footer-inner\">\n    <div class=\"footer-brand\">\n      <a class=\"nav-logo\" href=\"#\">Claim<span>Back</span></a>\n      <p>AI-powered health insurance appeal drafting tool. Built for India. Built using IRDAI regulations as reference.</p>\n    </div>\n    <div class=\"footer-col\">\n      <h5>Product</h5>\n      <a href=\"#why\">Why ClaimBack</a>\n      <a href=\"#how-it-works\">How It Works</a>\n      <a href=\"#output\">Sample Output</a>\n      <a href=\"#pricing\">Pricing</a>\n      <a href=\"#beta\">Join Beta</a>\n      <a href=\"#faq\">FAQ</a>\n    </div>\n    <div class=\"footer-col\">\n      <h5>Legal</h5>\n      <a href=\"terms.html\">Terms of Service</a>\n      <a href=\"privacy.html\">Privacy Policy</a>\n    </div>\n    <div class=\"footer-col\">\n      <h5>Contact</h5>\n      <a href=\"mailto:support@claimback.co.in\">support@claimback.co.in</a>\n      <a href=\"https://wa.me/919029004572\">WhatsApp Support</a>\n      <a href=\"mailto:support@claimback.co.in?subject=Corporate%20Enquiry%20-%20ClaimBack\">Corporate Enquiries</a>\n    </div>\n  </div>\n  <div class=\"footer-bottom\">\n    <span>© 2026 ClaimBack. All rights reserved.</span>\n    <span>🇮🇳 Made in India · AI-powered · Built using IRDAI regulations as reference</span>\n  </div>\n</footer>\n\n<script>\n  const observer = new IntersectionObserver((entries) => {\n    entries.forEach(e => { if(e.isIntersecting){ e.target.classList.add('visible'); observer.unobserve(e.target); }});\n  }, { threshold: 0.1 });\n  document.querySelectorAll('.reveal').forEach(el => observer.observe(el));\n</script>\n</body>\n</html>\n";
